GameConfig = {}

function GameConfig:loadConfig()
    GameConfig:loadGameConfig()

    TabsConfig:loadConfig()
    FitnessEquipConfig:loadConfig()
    GeneConfig:loadConfig()
    AdvancedConfig:loadConfig()
    SkillConfig:loadConfig()
    CommonConfig:loadConfig()
    UnitConfig:init(FileUtil.getConfigFromCsv("setting/Unit.csv", 2))
    EffectConfig:init(FileUtil.getConfigFromCsv("setting/Effect.csv", 2))
    ScaleFormulaConfig:init(FileUtil.getConfigFromCsv("setting/ScaleFormula.csv", 2))
    WallTextConfig:init(FileUtil.getConfigFromCsv("setting/WallText.csv", 2))
    PayShopTabsConfig:loadConfig()
    PayItemConfig:loadConfig()
    SkinConfig:loadConfig()
    NewGuideConfig:loadConfig()
    PayFitnessEquipConfig:loadConfig()
    TokenFitnessEquipConfig:loadConfig()
    TokenGeneConfig:loadConfig()
    TokenShopTabConfig:loadConfig()
    TokenSkillConfig:loadConfig()
    TokenSkinConfig:loadConfig()
end

function GameConfig:loadGameConfig()
    local config = FileUtil.getConfigFromYml("setting/ClientConfig.yml")
    if config == nil then
        return
    end

    GameConfig.grabCoe1 = tonumber(config.grabCoe1) or 1 --抓取缩放系数1
    GameConfig.grabCoe2 = tonumber(config.grabCoe2) or 1 --抓取缩放系数2
    GameConfig.adjustCoe = tonumber(config.adjustCoe) or 1 --抓取调节系数
    GameConfig.eventDlgLiveTime = tonumber(config.eventDlgLiveTime) or 5
    GameConfig.eventDlgDisableTime = tonumber(config.eventDlgDisableTime) or 3
    GameConfig.ConcealPowerScale = tonumber(config.ConcealPowerScale) or 1.0
    GameConfig.boyFreeSkinId = tonumber(config.boyFreeSkinId) or 1
    GameConfig.girlFreeSkinId = tonumber(config.girlFreeSkinId) or 2
    GameConfig.koEffect = config.koEffect or "129_victory.effect"
    GameConfig.koEffectTime = tonumber(config.koEffectTime) or 5000
    GameConfig.CameraDistanceMaxCoe = tonumber(config.CameraDistanceMaxCoe) or 50
    GameConfig.showFloatNumberPosCoe = tonumber(config.showFloatNumberPosCoe) or 1 --伤害飘字位置系数
    GameConfig.UpperActionPlaySkill = StringUtil.split(config.UpperActionPlaySkill, ",") or {}
    GameConfig.SkillCd = tonumber(config.SkillCd) or 1
    GameConfig.concealPowerCameraDistanceMax = tonumber(config.concealPowerCameraDistanceMax) or 50
    GameConfig.showFloatNumberScaleCoeHurter = tonumber(config.showFloatNumberScaleCoeHurter) or 1 --被击者
    GameConfig.showFloatNumberScaleCoeAttacker = tonumber(config.showFloatNumberScaleCoeAttacker) or 1 --攻击者
    GameConfig.showFloatNumberTime = tonumber(config.showFloatNumberTime) or 500 --飘字时间
    GameConfig.attackCdTime = tonumber(config.attackCdTime) or 1000 --攻击CD
    GameConfig.TeamRangeEffect = config.TeamRangeEffect or "hero_select.effect"
    GameConfig.TeamEffectScale = config.TeamEffectScale or 5
    GameConfig.guideSellMuscleMass = config.guideSellMuscleMass or 15
    GameConfig.guideShopGold = config.guideShopGold or 15
    GameConfig.championshipsLvConfig = config.championshipsLvConfig or {}
    GameConfig.maxScale = tonumber(config.maxScale) or 90 --最大缩放值
    GameConfig.championshipsNextBtnCd = tonumber(config.championshipsNextBtnCd) or 3

    --锦标赛相关
    GameConfig.btnChampionShipShowLevel = tonumber(config.btnChampionShipShowLevel) or 301 --锦标赛按钮显示需要的进阶等级
    GameConfig.btnChampionShipEnableLevel = tonumber(config.btnChampionShipEnableLevel) or 301 --锦标赛按钮可点击需要的进阶等级
    GameConfig.btnChampionShipEnableMuscle = tonumber(config.btnChampionShipEnableMuscle) or 0 --锦标赛按钮可点击需要的肌肉量

    ClientHelper.putFloatPrefs("ConcealPowerScale", GameConfig.ConcealPowerScale)
    ClientHelper.putIntPrefs("ShowFloatNumberTime", GameConfig.showFloatNumberTime)

    --LogUtil.log("GameConfig " .. inspect.inspect(GameConfig))
end